#include <stdio.h>
#include <string.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char S[1005];
        if (scanf("%s", S) != 1) break; // strings have no spaces
        int sum = 0;
        for (int i = 0; S[i] != '\0'; ++i) {
            if (S[i] >= '0' && S[i] <= '9') {
                sum += S[i] - '0';
            }
        }
        printf("%d\n", sum);
    }
    return 0;
}

