import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0])
    out_lines = []
    for i in range(1, T + 1):
        S = data[i].strip()
        total = 0
        for ch in S:
            if '0' <= ch <= '9':
                total += ord(ch) - ord('0')
        out_lines.append(str(total))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

